def _is_style_line(line: str) -> bool:
    lowered = line.lower()
    if lowered in ("end",):
        return True
    return lowered.startswith(
        (
            "classdef ",
            "class ",
            "style ",
            "linkstyle ",
            "click ",
            "subgraph ",
            "direction ",
        )
    )

