def _listen_for_keyboard_thread(
    cancel: threading.Event,
    pause: threading.Event,
    paused: threading.Event,
    emit: Callable[[KeyEvent], None],
) -> None:
    if sys.platform == "win32":
        _listen_for_keyboard_windows(cancel, pause, paused, emit)
    else:
        _listen_for_keyboard_unix(cancel, pause, paused, emit)

def _listen_for_keyboard_unix(
    cancel: threading.Event,
    pause: threading.Event,
    paused: threading.Event,
    emit: Callable[[KeyEvent], None],
) -> None:
    if sys.platform == "win32":
        raise RuntimeError("Unix keyboard listener requires a non-Windows platform")

    import termios

    fd = sys.stdin.fileno()
    oldterm = termios.tcgetattr(fd)
    rawattr = termios.tcgetattr(fd)
    rawattr[3] = rawattr[3] & ~termios.ICANON & ~termios.ECHO
    rawattr[6][termios.VMIN] = 0
    rawattr[6][termios.VTIME] = 0
    raw_enabled = False

    def enable_raw() -> None:
        nonlocal raw_enabled
        if raw_enabled:
            return
        termios.tcsetattr(fd, termios.TCSANOW, rawattr)
        raw_enabled = True

    def disable_raw() -> None:
        nonlocal raw_enabled
        if not raw_enabled:
            return
        termios.tcsetattr(fd, termios.TCSANOW, oldterm)
        raw_enabled = False

    enable_raw()

    try:
        while not cancel.is_set():
            if pause.is_set():
                disable_raw()
                paused.set()
                time.sleep(0.01)
                continue
            if paused.is_set():
                paused.clear()
                enable_raw()

            try:
                c = sys.stdin.buffer.read(1)
            except (OSError, ValueError):
                c = b""

            if not c:
                if cancel.is_set():
                    break
                time.sleep(0.01)
                continue

            if c == b"\x1b":
                sequence = c
                for _ in range(2):
                    if cancel.is_set():
                        break
                    try:
                        fragment = sys.stdin.buffer.read(1)
                    except (OSError, ValueError):
                        fragment = b""
                    if not fragment:
                        break
                    sequence += fragment
                    if sequence in _ARROW_KEY_MAP:
                        break

                event = _ARROW_KEY_MAP.get(sequence)
                if event is not None:
                    emit(event)
                elif sequence == b"\x1b":
                    emit(KeyEvent.ESCAPE)
            elif c in (b"\r", b"\n"):
                emit(KeyEvent.ENTER)
            elif c == b" ":
                emit(KeyEvent.SPACE)
            elif c == b"\t":
                emit(KeyEvent.TAB)
            elif c == b"\x05":  # Ctrl+E
                emit(KeyEvent.CTRL_E)
            elif c == b"1":
                emit(KeyEvent.NUM_1)
            elif c == b"2":
                emit(KeyEvent.NUM_2)
            elif c == b"3":
                emit(KeyEvent.NUM_3)
            elif c == b"4":
                emit(KeyEvent.NUM_4)
            elif c == b"5":
                emit(KeyEvent.NUM_5)
    finally:
        termios.tcsetattr(fd, termios.TCSAFLUSH, oldterm)

