def _listen_for_keyboard_windows(
    cancel: threading.Event,
    pause: threading.Event,
    paused: threading.Event,
    emit: Callable[[KeyEvent], None],
) -> None:
    if sys.platform != "win32":
        raise RuntimeError("Windows keyboard listener requires a Windows platform")

    import msvcrt

    while not cancel.is_set():
        if pause.is_set():
            paused.set()
            time.sleep(0.01)
            continue
        if paused.is_set():
            paused.clear()

        if msvcrt.kbhit():
            c = msvcrt.getch()

            # Handle special keys (arrow keys, etc.)
            if c in (b"\x00", b"\xe0"):
                # Extended key, read the next byte
                extended = msvcrt.getch()
                event = _WINDOWS_KEY_MAP.get(extended)
                if event is not None:
                    emit(event)
            elif c == b"\x1b":
                sequence = c
                for _ in range(2):
                    if cancel.is_set():
                        break
                    fragment = msvcrt.getch() if msvcrt.kbhit() else b""
                    if not fragment:
                        break
                    sequence += fragment
                    if sequence in _ARROW_KEY_MAP:
                        break

                event = _ARROW_KEY_MAP.get(sequence)
                if event is not None:
                    emit(event)
                elif sequence == b"\x1b":
                    emit(KeyEvent.ESCAPE)
            elif c in (b"\r", b"\n"):
                emit(KeyEvent.ENTER)
            elif c == b" ":
                emit(KeyEvent.SPACE)
            elif c == b"\t":
                emit(KeyEvent.TAB)
            elif c == b"\x05":  # Ctrl+E
                emit(KeyEvent.CTRL_E)
            elif c == b"1":
                emit(KeyEvent.NUM_1)
            elif c == b"2":
                emit(KeyEvent.NUM_2)
            elif c == b"3":
                emit(KeyEvent.NUM_3)
            elif c == b"4":
                emit(KeyEvent.NUM_4)
            elif c == b"5":
                emit(KeyEvent.NUM_5)
        else:
            if cancel.is_set():
                break
            time.sleep(0.01)

