def _format_tag(tag: str, attrs: Mapping[str, str | None] | None = None) -> str:
    if not attrs:
        return f"<{tag}>"
    rendered: list[str] = []
    for key, value in sorted(attrs.items()):
        if not value:
            continue
        rendered.append(f'{key}="{escape(str(value), quote=True)}"')
    if not rendered:
        return f"<{tag}>"
    return f"<{tag} " + " ".join(rendered) + ">"

