def parse_bearer_token(value: str | None) -> str | None:
    """Extract bearer token from Authorization header."""
    if not value:
        return None
    scheme, _, token = value.partition(" ")
    if scheme.lower() != "bearer":
        return None
    token = token.strip()
    return token or None

