def normalize_allowed_origins(value: str | None) -> list[str]:
    """Parse comma-separated origins into a normalized list."""
    if not value:
        return []
    origins: list[str] = []
    for raw in value.split(","):
        origin = raw.strip().rstrip("/")
        if origin:
            origins.append(origin)
    return origins

