tests_e2e.wire_helpers.LineReader.source_code:
class LineReader:
    def __init__(self, stream: IO[str]) -> None:
        # Use a background reader so Windows pipes don't rely on select().
        self._stream = stream
        self._queue: queue.Queue[str | None] = queue.Queue()
        self._thread = threading.Thread(target=self._run, daemon=True)
        self._thread.start()

    def _run(self) -> None:
        try:
            for line in self._stream:
                self._queue.put(line)
        except Exception:
            self._queue.put(None)
            return
        self._queue.put(None)

    def read_line(self, timeout: float) -> str | None:
        return self._queue.get(timeout=timeout)

    def close(self) -> None:
        with contextlib.suppress(Exception):
            self._stream.close()
        self._thread.join(timeout=0.5)

tests_e2e.wire_helpers.WireProcess.source_code:
class WireProcess:
    process: subprocess.Popen[str]
    reader: LineReader

    def send_json(self, payload: dict[str, Any]) -> None:
        assert self.process.stdin is not None
        line = json.dumps(payload)
        _print_trace("STDIN", line)
        self.process.stdin.write(line + "\n")
        self.process.stdin.flush()

    def send_raw(self, line: str) -> None:
        assert self.process.stdin is not None
        _print_trace("STDIN", line)
        self.process.stdin.write(line + "\n")
        self.process.stdin.flush()

    def read_json(self, timeout: float = DEFAULT_TIMEOUT) -> dict[str, Any]:
        deadline = time.monotonic() + timeout
        while True:
            remaining = deadline - time.monotonic()
            if remaining <= 0:
                raise TimeoutError("Timed out waiting for wire output")
            try:
                line = self.reader.read_line(timeout=remaining)
            except queue.Empty:
                continue
            if line is None:
                raise EOFError("Wire process closed output stream")
            line = line.strip()
            if not line:
                continue
            _print_trace("STDOUT", line)
            try:
                msg = json.loads(line)
            except json.JSONDecodeError:
                continue
            if isinstance(msg, dict):
                return msg

    def close(self) -> None:
        if self.process.stdin is not None:
            with contextlib.suppress(Exception):
                self.process.stdin.close()
        self.reader.close()
        if self.process.stdout is not None:
            with contextlib.suppress(Exception):
                self.process.stdout.close()
        try:
            self.process.wait(timeout=2)
        except subprocess.TimeoutExpired:
            self.process.terminate()
            try:
                self.process.wait(timeout=2)
            except subprocess.TimeoutExpired:
                self.process.kill()
                self.process.wait()

