async function highlightCode(
  code: string,
  language: string,
  showLineNumbers = false,
  lineNumbers?: number[],
): Promise<HighlightCacheEntry | null> {
  const { bundledLanguages, codeToHtml } = await loadShikiModule();
  if (!isBundledLanguage(bundledLanguages, language)) {
    return null;
  }

  const transformers: ShikiTransformer[] =
    showLineNumbers || (lineNumbers && lineNumbers.length > 0)
      ? [makeLineNumberTransformer(lineNumbers)]
      : [];

  const [light, dark] = await Promise.all([
    codeToHtml(code, {
      lang: language,
      theme: "one-light",
      transformers,
    }),
    codeToHtml(code, {
      lang: language,
      theme: "one-dark-pro",
      transformers,
    }),
  ]);

  return { light, dark };
}

type CodeBlockDownloadButtonProps = ComponentProps<typeof Button> & {
  language?: string;
  filename?: string;
  mimeType?: string;
  onDownload?: (filename: string) => void;
  onError?: (error: Error) => void;
};

CodeBlockDownloadButton = ({
  ref,
  language,
  filename,
  mimeType = "text/plain",
  onDownload,
  onError,
  children,
  className,
  ...props
}: CodeBlockDownloadButtonProps) => {
  const { code } = useContext(CodeBlockContext);
  const resolvedFilename = filename ?? getDownloadFilename(language);

  const handleDownload = () => {
    if (typeof window === "undefined" || typeof document === "undefined") {
      onError?.(new Error("Download is not available"));
      return;
    }

    try {
      const blob = new Blob([code], { type: mimeType });
      const url = URL.createObjectURL(blob);
      const anchor = document.createElement("a");
      anchor.href = url;
      anchor.download = resolvedFilename;
      document.body.appendChild(anchor);
      anchor.click();
      document.body.removeChild(anchor);
      setTimeout(() => URL.revokeObjectURL(url), 0);
      onDownload?.(resolvedFilename);
    } catch (error) {
      const err =
        error instanceof Error ? error : new Error("Failed to download code");
      onError?.(err);
    }
  };

  return (
    <Button
      ref={ref}
      className={cn("shrink-0", className)}
      onClick={handleDownload}
      size="icon-xs"
      variant="ghost"
      {...props}
    >
      {children ?? <DownloadIcon className="size-3.5" />}
    </Button>
  );
}

type CodeBlockPreviewButtonProps = ComponentProps<typeof Button> & {
  onPreview?: () => void;
  onError?: (error: Error) => void;
};

CodeBlockPreviewButton = ({
  ref,
  onPreview,
  onError,
  children,
  className,
  ...props
}: CodeBlockPreviewButtonProps) => {
  const { code } = useContext(CodeBlockContext);

  const handlePreview = () => {
    if (typeof window === "undefined") {
      onError?.(new Error("Preview is not available"));
      return;
    }

    try {
      const blob = new Blob([code], { type: "text/html" });
      const url = URL.createObjectURL(blob);
      window.open(url, "_blank");
      setTimeout(() => URL.revokeObjectURL(url), 5000);
      onPreview?.();
    } catch (error) {
      const err =
        error instanceof Error ? error : new Error("Failed to preview");
      onError?.(err);
    }
  };

  return (
    <Button
      ref={ref}
      className={cn("shrink-0", className)}
      onClick={handlePreview}
      size="icon-xs"
      variant="ghost"
      {...props}
    >
      {children ?? <ExternalLinkIcon className="size-3.5" />}
    </Button>
  );
}

