isSimilarEnough = (
  a: string,
  b: string,
  maxChangeRatio: number,
): boolean => {
  if (maxChangeRatio <= 0) return a === b;
  if (maxChangeRatio >= 1) return true;
  return calculateChangeRatio(a, b) <= maxChangeRatio;
}

