type AssistantApprovalHandler = (
  approval: ToolApproval,
  decision: ApprovalResponseDecision,
) => void | Promise<void>;

function AssistantMessage({
  message,
  pendingApprovalMap,
  onApprovalAction,
  canRespondToApproval,
  blocksExpanded,
}: AssistantMessageProps) {
  const content = useMemo(() => {
    switch (message.variant) {
      case "chain-of-thought":
        return renderChainOfThoughtMessage(message);
      case "tool":
        return renderToolMessage({
          message,
          pendingApprovalMap,
          onApprovalAction,
          canRespondToApproval,
          blocksExpanded,
        });
      case "code":
        return renderCodeMessage(message);
      case "thinking":
        return renderThinkingMessage(message, blocksExpanded);
      default:
        return renderAssistantText(message);
    }
  }, [
    message,
    pendingApprovalMap,
    onApprovalAction,
    canRespondToApproval,
    blocksExpanded,
  ]);

  return content;
}

