web.src.hooks.wireTypes.parseWireMessage.source_code:
function parseWireMessages(jsonlContent: string): WireMessage[] {
  const lines = jsonlContent.trim().split("\n");
  const messages: WireMessage[] = [];

  for (const line of lines) {
    if (!line.trim()) continue;
    try {
      const parsed = JSON.parse(line) as WireMessage;
      if (parsed.jsonrpc === "2.0") {
        messages.push(parsed);
      }
    } catch {
      console.warn("Failed to parse wire message:", line);
    }
  }

  return messages;
}

web.src.hooks.wireTypes.extractEvent.source_code:
function extractEvent(message: WireMessage): WireEvent | null {
  if (message.method !== "event" || !message.params) {
    return null;
  }

  const params = message.params as { type: string; payload: unknown };
  const type = EVENT_TYPE_ALIASES[params.type] ?? params.type;
  return {
    type,
    payload: params.payload,
  } as WireEvent;
}

