web.src.lib.apiClient.formatValidationEr.source_code:
function formatValidationError(detail: unknown): string {
  if (Array.isArray(detail)) {
    return detail
      .map((err) => {
        if (err && typeof err === "object" && "msg" in err) {
          const loc = Array.isArray(err.loc) ? err.loc.slice(1).join(".") : "";
          return loc ? `${loc}: ${err.msg}` : err.msg;
        }
        return String(err);
      })
      .join("; ");
  }
  if (typeof detail === "string") {
    return detail;
  }
  return "Validation failed";
}

web.src.lib.apiClient.createConfig.source_code:
function createConfig(): Configuration {
  return new Configuration({
    basePath: getApiBaseUrl(),
    middleware: [
      {
        pre: async (context: RequestContext) => {
          context.init.headers = {
            ...context.init.headers,
            ...getAuthHeader(),
          };
          return context;
        },
        post: async (context: ResponseContext) => {
          if (!context.response.ok) {
            const data = await context.response.json();
            let message: string;

            if (context.response.status === 422 && data.detail) {
              // FastAPI validation error
              message = formatValidationError(data.detail);
            } else if (typeof data.detail === "string") {
              message = data.detail;
            } else if (typeof data.msg === "string") {
              message = data.msg;
            } else {
              message = "Request failed";
            }

            switch (context.response.status) {
              case 401:
                console.error("Authentication failed. Please login again.");
                break;
              case 403:
                console.error(message);
                break;
              case 404:
                console.error("The requested resource was not found.");
                break;
              default:
                console.error(message);
            }

            throw new Error(message);
          }
          return context.response;
        },
      },
    ],
  });
}

web.src.lib.auth.getAuthToken.source_code:
function getAuthToken(): string | null {
  const token = localStorage.getItem(AUTH_TOKEN_KEY);
  if (!token) {
    return null;
  }

  // Check if token has expired
  const timestamp = localStorage.getItem(AUTH_TOKEN_TIMESTAMP_KEY);
  if (timestamp) {
    const storedAt = parseInt(timestamp, 10);
    if (Number.isNaN(storedAt)) {
      // Treat non-parsable timestamps as expired/corrupted
      clearAuthToken();
      return null;
    }
    const age = Date.now() - storedAt;
    if (age > TOKEN_EXPIRY_MS) {
      clearAuthToken();
      return null;
    }
  }

  return token;
}

web.src.lib.auth.setAuthToken.source_code:
function setAuthToken(token: string): void {
  localStorage.setItem(AUTH_TOKEN_KEY, token);
  localStorage.setItem(AUTH_TOKEN_TIMESTAMP_KEY, Date.now().toString());
}

web.src.lib.auth.consumeAuthTokenFromUrl.source_code:
function consumeAuthTokenFromUrl(): string | null {
  const url = new URL(window.location.href);
  const token = url.searchParams.get(AUTH_TOKEN_PARAM);
  if (!token) {
    return null;
  }
  url.searchParams.delete(AUTH_TOKEN_PARAM);
  window.history.replaceState({}, "", url.toString());
  return token;
}

web.src.lib.auth.getAuthHeader.source_code:
function getAuthHeader(): Record<string, string> {
  let token = getAuthToken();
  // Fallback: try reading from URL if localStorage is empty
  if (!token) {
    const url = new URL(window.location.href);
    token = url.searchParams.get(AUTH_TOKEN_PARAM);
  }
  if (!token) {
    return {};
  }
  return { Authorization: `Bearer ${token}` };
}

web.src.lib.utils.shortenTitle.source_code:
function shortenTitle(
  title: string | undefined | null,
  maxLength = 50,
): string {
  if (!title) return "";

  // Normalize: collapse whitespace and trim
  const normalized = title.replace(/\s+/g, " ").trim();

  if (normalized.length <= maxLength) {
    return normalized;
  }

  // Shorten with ellipsis
  return `${normalized.slice(0, maxLength - 1)}…`;
}

